#!/usr/bin/env node
/**
 * Renders the per-PR report index page for GitHub Pages.
 *
 * Usage: node render-pr-index.mjs <staging-dir>
 * Env (passed via env: in the workflow, never inlined into run:):
 *   PR_NUMBER         — pull request number
 *   HEAD_SHA          — PR head commit
 *   RUN_URL           — link to the generating workflow run
 *   CLIENT_ASSETS_DIR — built client assets dir; gzip total is computed from it
 *
 * Writes <staging-dir>/index.html and <staging-dir>/summary.json (consumed by
 * render-reports-comment.mjs in the publish job).
 */
import { existsSync, readFileSync, readdirSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { gzipSync } from "node:zlib";

const [, , stagingDir] = process.argv;
const { PR_NUMBER, HEAD_SHA, RUN_URL, CLIENT_ASSETS_DIR } = process.env;

// One entry per report kind; `always` entries are listed even when absent in
// staging (mutation is deployed into the same pr dir by its own workflow).
const MANIFEST = [
  {
    path: "coverage/domain/index.html",
    title: "Test coverage — @jigswap/domain",
    description: "Vitest v8 line/branch coverage for the domain package.",
  },
  {
    path: "coverage/backend/index.html",
    title: "Test coverage — @jigswap/backend",
    description: "Vitest v8 line/branch coverage for the Convex backend.",
  },
  {
    path: "bundle/stats.html",
    title: "Bundle treemap — apps/web",
    description: "Client bundle composition (gzip + brotli sizes).",
  },
  {
    path: "deps/domain-deps.html",
    title: "Dependency graph — domain contexts",
    description: "dependency-cruiser view of the DDD context boundaries.",
  },
  {
    path: "mutation/mutation-report.html",
    title: "Mutation testing — @jigswap/domain",
    description: "Stryker mutation report.",
    always: true,
    note: "Generated by its own workflow, only when packages/domain changes — may be absent on this PR.",
  },
];

function coveragePct(pkg) {
  try {
    const summary = JSON.parse(
      readFileSync(
        join(stagingDir, "coverage", pkg, "coverage-summary.json"),
        "utf8",
      ),
    );
    return summary.total?.lines?.pct ?? null;
  } catch {
    return null;
  }
}

function bundleGzipBytes() {
  if (!CLIENT_ASSETS_DIR || !existsSync(CLIENT_ASSETS_DIR)) return null;
  let total = 0;
  for (const entry of readdirSync(CLIENT_ASSETS_DIR, {
    recursive: true,
    withFileTypes: true,
  })) {
    if (!entry.isFile() || !/\.(js|css)$/.test(entry.name)) continue;
    total += gzipSync(readFileSync(join(entry.parentPath, entry.name))).length;
  }
  return total;
}

const summary = {
  pr: PR_NUMBER ?? null,
  headSha: HEAD_SHA ?? null,
  runUrl: RUN_URL ?? null,
  generatedAt: new Date().toISOString(),
  coverage: {
    domain: coveragePct("domain"),
    backend: coveragePct("backend"),
  },
  bundleGzipBytes: bundleGzipBytes(),
};
writeFileSync(
  join(stagingDir, "summary.json"),
  `${JSON.stringify(summary, null, 2)}\n`,
);

const esc = (s) =>
  String(s).replace(
    /[&<>"]/g,
    (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" })[c],
  );

const items = MANIFEST.filter(
  (entry) => entry.always || existsSync(join(stagingDir, entry.path)),
)
  .map(
    (entry) => `      <li>
        <a href="./${entry.path}">${esc(entry.title)}</a>
        <p>${esc(entry.description)}${entry.note ? ` <em>${esc(entry.note)}</em>` : ""}</p>
      </li>`,
  )
  .join("\n");

const kb = (b) => `${(b / 1024).toFixed(1)} kB`;
const facts = [
  summary.coverage.domain !== null &&
    `domain coverage ${summary.coverage.domain}%`,
  summary.coverage.backend !== null &&
    `backend coverage ${summary.coverage.backend}%`,
  summary.bundleGzipBytes !== null &&
    `client bundle ${kb(summary.bundleGzipBytes)} gzipped`,
]
  .filter(Boolean)
  .join(" · ");

const html = `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <meta name="robots" content="noindex" />
  <title>CI reports — PR #${esc(PR_NUMBER ?? "?")}</title>
  <style>
    body { font-family: system-ui, sans-serif; max-width: 46rem; margin: 3rem auto; padding: 0 1rem; color: #1f2328; }
    h1 { font-size: 1.4rem; }
    .meta { color: #59636e; font-size: 0.85rem; }
    ul { padding-left: 1.2rem; }
    li { margin: 0.8rem 0; }
    li p { margin: 0.15rem 0 0; color: #59636e; font-size: 0.9rem; }
    a { color: #0969da; }
  </style>
</head>
<body>
  <h1>CI reports — PR #${esc(PR_NUMBER ?? "?")}</h1>
  <p class="meta">
    ${HEAD_SHA ? `commit <code>${esc(HEAD_SHA.slice(0, 7))}</code> · ` : ""}generated ${esc(summary.generatedAt)}${RUN_URL ? ` · <a href="${esc(RUN_URL)}">workflow run</a>` : ""}
    ${facts ? `<br />${esc(facts)}` : ""}
  </p>
  <ul>
${items}
  </ul>
</body>
</html>
`;
writeFileSync(join(stagingDir, "index.html"), html);
console.error(`index.html + summary.json written to ${stagingDir}`);
